DECLARE @StudentIds TABLE (StudentId INT); DECLARE @UserIds TABLE (UserId INT); INSERT INTO @UserIds (UserId) SELECT u.UserId FROM users u INNER JOIN roles r ON u.RoleId = r.RoleId WHERE r.Name = 'Student' AND u.Email NOT IN ('youssef@student.com', 'salma@student.com'); INSERT INTO @StudentIds (StudentId) SELECT StudentId FROM students WHERE UserId IN (SELECT UserId FROM @UserIds); DELETE FROM parent_students WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM student_classes WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM student_answers WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM student_exams WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM student_performances WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM ai_recommendations WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM attendances WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM student_enrollments WHERE StudentId IN (SELECT StudentId FROM @StudentIds); DELETE FROM refresh_tokens WHERE UserId IN (SELECT UserId FROM @UserIds); DELETE FROM notifications WHERE UserId IN (SELECT UserId FROM @UserIds); DELETE FROM subscriptions WHERE UserId IN (SELECT UserId FROM @UserIds); DELETE FROM students WHERE UserId IN (SELECT UserId FROM @UserIds); DELETE FROM users WHERE UserId IN (SELECT UserId FROM @UserIds);
